import type { HostStore, Serializer, Storage } from './types'

/**
 * Create a empty storage.
 * @returns
 */
export function createEmptyStorage<T>(): Storage<T> {
  return { load: () => null, dump: () => {} }
}

/**
 * Create a storage.
 *
 * @param store
 * @param key
 * @param serializer
 * @returns
 */
export function createStorage<T>(
  store: HostStore,
  key: string,
  serializer: Serializer<T>,
): Storage<T> {
  return { load, dump }

  function load(): T | null {
    const content = store.get(key)
    if (content == null) return null
    return serializer.parse(content)
  }

  function dump(data: T): void {
    const content: string = serializer.stringify(data)
    store.set(key, content)
  }
}
