/**
 * Create a random number in the range [min, max).
 * @param min
 * @param max
 * @returns
 */
export function random(min: number, max: number): number {
  return Math.random() * (max - min) + min
}

/**
 * Create a random rgb color.
 */
export function randomRGB(
  options: {
    red?: number
    green?: number
    blue?: number
  } = {},
): string {
  const {
    red = random(0, 255).toFixed(0),
    green = random(0, 255).toFixed(0),
    blue = random(0, 255).toFixed(0),
  } = options
  return `rgb(${red},${green},${blue})`
}

/**
 * Create a random rgba color.
 */
export function randomRGBA(
  options: {
    red?: number
    green?: number
    blue?: number
    alpha?: number
  } = {},
): string {
  const {
    red = random(0, 255).toFixed(0),
    green = random(0, 255).toFixed(0),
    blue = random(0, 255).toFixed(0),
    alpha = Math.random().toFixed(2),
  } = options
  return `rgba(${red},${green},${blue},${alpha})`
}

/**
 * Create a random hsl color.
 */
export function randomHSL(
  options: {
    hue?: number
    saturate?: number
    lightness?: number
  } = {},
): string {
  const {
    hue = random(0, 360).toFixed(0),
    saturate = random(0, 100).toFixed(0),
    lightness = random(0, 100).toFixed(0),
  } = options
  return `hsl(${hue}deg,${saturate}%,${lightness}%)`
}

/**
 * Create a random hsla color.
 */
export function randomHSLA(
  options: {
    hue?: number
    saturate?: number
    lightness?: number
    alpha?: number
  } = {},
): string {
  const {
    hue = random(0, 360).toFixed(0),
    saturate = random(0, 100).toFixed(0),
    lightness = random(0, 100).toFixed(0),
    alpha = Math.random().toFixed(2),
  } = options
  return `hsla(${hue}deg,${saturate}%,${lightness}%,${alpha})`
}
